// 3. Implement AOP aspect for automatic audit logging
package com.ansvar.security.audit;

import com.fasterxml.jackson.databind.ObjectMapper;
import jakarta.servlet.http.HttpServletRequest;
import org.aspectj.lang.ProceedingJoinPoint;
import org.aspectj.lang.annotation.*;
import org.aspectj.lang.reflect.MethodSignature;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.context.request.RequestContextHolder;
import org.springframework.web.context.request.ServletRequestAttributes;

import java.time.Instant;
import java.util.HashMap;
import java.util.Map;

@Aspect
@Component
public class AuditLogAspect {

    private static final Logger logger = LoggerFactory.getLogger(AuditLogAspect.class);
    private final AuditEventRepository auditRepository;
    private final ObjectMapper objectMapper;

    public AuditLogAspect(AuditEventRepository auditRepository, ObjectMapper objectMapper) {
        this.auditRepository = auditRepository;
        this.objectMapper = objectMapper;
    }

    @Around("@annotation(auditLog)")
    public Object logAudit(ProceedingJoinPoint joinPoint, AuditLog auditLog) throws Throwable {
        AuditEvent event = new AuditEvent();
        event.setTimestamp(Instant.now());
        event.setAction(auditLog.action());
        event.setResourceType(auditLog.resourceType());

        // Capture user context
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null && auth.isAuthenticated()) {
            event.setUserId(auth.getName());
        } else {
            event.setUserId("anonymous");
        }

        // Capture HTTP context
        ServletRequestAttributes attributes = (ServletRequestAttributes) 
            RequestContextHolder.getRequestAttributes();
        if (attributes != null) {
            HttpServletRequest request = attributes.getRequest();
            event.setIpAddress(getClientIp(request));
            event.setUserAgent(request.getHeader("User-Agent"));
        }

        // Capture method arguments
        if (auditLog.includeArgs()) {
            Object[] args = joinPoint.getArgs();
            Map<String, Object> argsMap = new HashMap<>();
            MethodSignature signature = (MethodSignature) joinPoint.getSignature();
            String[] paramNames = signature.getParameterNames();

            for (int i = 0; i < args.length; i++) {
                if (args[i] != null && !isSensitiveParameter(paramNames[i])) {
                    argsMap.put(paramNames[i], sanitizeForLog(args[i]));
                }
            }
            event.setRequestDetails(objectMapper.writeValueAsString(argsMap));
        }

        // Execute method and capture result
        Object result = null;
        try {
            result = joinPoint.proceed();
            event.setStatus(AuditStatus.SUCCESS);

            if (auditLog.includeResult() && result != null) {
                event.setResponseDetails(objectMapper.writeValueAsString(sanitizeForLog(result)));
            }

            // Extract resource ID from result if available
            if (result != null && hasIdField(result)) {
                event.setResourceId(extractId(result));
            }

        } catch (Exception e) {
            event.setStatus(AuditStatus.FAILURE);
            event.setErrorMessage(e.getMessage());
            throw e; // Re-throw to maintain normal exception handling
        } finally {
            // Always persist audit event
            try {
                auditRepository.save(event);
                logger.info("Audit log created: action={}, user={}, status={}", 
                    event.getAction(), event.getUserId(), event.getStatus());
            } catch (Exception e) {
                logger.error("Failed to persist audit event", e);
                // Don't fail the business operation due to audit logging failure
            }
        }

        return result;
    }

    private String getClientIp(HttpServletRequest request) {
        String ip = request.getHeader("X-Forwarded-For");
        if (ip == null || ip.isEmpty()) {
            ip = request.getRemoteAddr();
        } else {
            ip = ip.split(",")[0].trim();
        }
        return ip;
    }

    private boolean isSensitiveParameter(String paramName) {
        return paramName != null && (
            paramName.toLowerCase().contains("password") ||
            paramName.toLowerCase().contains("secret") ||
            paramName.toLowerCase().contains("token") ||
            paramName.toLowerCase().contains("credential")
        );
    }

    private Object sanitizeForLog(Object obj) {
        // Implement logic to redact sensitive fields
        // Return simplified version for logging
        return obj;
    }

    private boolean hasIdField(Object obj) {
        try {
            obj.getClass().getMethod("getId");
            return true;
        } catch (NoSuchMethodException e) {
            return false;
        }
    }

    private String extractId(Object obj) {
        try {
            Object id = obj.getClass().getMethod("getId").invoke(obj);
            return id != null ? id.toString() : null;
        } catch (Exception e) {
            return null;
        }
    }
}

