# Terraform configuration for comprehensive CloudTrail setup

resource "aws_cloudtrail" "main" {
  name                          = "ansvar-audit-trail"
  s3_bucket_name                = aws_s3_bucket.cloudtrail.id
  include_global_service_events = true
  is_multi_region_trail         = true
  enable_log_file_validation    = true # Cryptographic log integrity

  # Enable data event logging for S3 and Lambda
  event_selector {
    read_write_type           = "All"
    include_management_events = true

    # Log all S3 object-level operations
    data_resource {
      type   = "AWS::S3::Object"
      values = ["arn:aws:s3:::ansvar-customer-data/*"]
    }

    # Log all Lambda function invocations
    data_resource {
      type   = "AWS::Lambda::Function"
      values = ["arn:aws:lambda:*:${data.aws_caller_identity.current.account_id}:function/*"]
    }
  }

  # Enable CloudWatch Logs integration for real-time monitoring
  cloud_watch_logs_group_arn = "${aws_cloudwatch_log_group.cloudtrail.arn}:*"
  cloud_watch_logs_role_arn  = aws_iam_role.cloudtrail_cloudwatch.arn

  # Enable Insights for anomaly detection
  insight_selector {
    insight_type = "ApiCallRateInsight"
  }

  tags = {
    Environment = "production"
    Compliance  = "PCI-DSS,SOC2,ISO27001"
  }
}

# S3 bucket for CloudTrail logs with strict security
resource "aws_s3_bucket" "cloudtrail" {
  bucket = "ansvar-cloudtrail-logs-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "cloudtrail" {
  bucket = aws_s3_bucket.cloudtrail.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "cloudtrail" {
  bucket = aws_s3_bucket.cloudtrail.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.cloudtrail.arn
    }
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "cloudtrail" {
  bucket = aws_s3_bucket.cloudtrail.id

  rule {
    id     = "log-retention"
    status = "Enabled"

    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    transition {
      days          = 365
      storage_class = "DEEP_ARCHIVE"
    }

    expiration {
      days = 2555 # 7 years for PCI-DSS compliance
    }
  }
}

