package com.ansvar.security.logging;

public enum SecurityEvent {
    LOGIN_SUCCESS("user.login.success", "INFO"),
    LOGIN_FAILURE("user.login.failure", "WARN"),
    PRIVILEGE_ESCALATION("user.privilege.escalation", "CRITICAL"),
    UNAUTHORIZED_ACCESS("access.unauthorized", "WARN"),
    DATA_EXPORT("data.export", "INFO"),
    SENSITIVE_DATA_ACCESS("data.sensitive.access", "INFO"),
    CONFIGURATION_CHANGE("config.change", "WARN"),
    ACCOUNT_LOCKED("account.locked", "WARN"),
    PASSWORD_RESET("password.reset", "INFO"),
    API_KEY_CREATED("apikey.created", "INFO"),
    API_KEY_REVOKED("apikey.revoked", "WARN");

    private final String eventCode;
    private final String severity;

    SecurityEvent(String eventCode, String severity) {
        this.eventCode = eventCode;
        this.severity = severity;
    }

    public String getEventCode() { return eventCode; }
    public String getSeverity() { return severity; }
}

