package com.ansvar.security.logging;

import net.logstash.logback.argument.StructuredArguments;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.util.HashMap;
import java.util.Map;

@Service
public class SecurityLogger {

    private static final Logger logger = LoggerFactory.getLogger("SECURITY_AUDIT");

    public void logSecurityEvent(SecurityEvent event, String userId, 
                                String resourceType, String resourceId, 
                                Map<String, Object> additionalData) {
        Map<String, Object> logData = new HashMap<>();
        logData.put("event_type", event.getEventCode());
        logData.put("severity", event.getSeverity());
        logData.put("user_id", userId);
        logData.put("resource_type", resourceType);
        logData.put("resource_id", resourceId);
        logData.put("timestamp", System.currentTimeMillis());

        if (additionalData != null) {
            logData.putAll(additionalData);
        }

        logger.info("Security event: {}", 
            StructuredArguments.entries(logData));
    }

    public void logLoginAttempt(String username, String ipAddress, boolean success) {
        Map<String, Object> data = new HashMap<>();
        data.put("ip_address", ipAddress);
        data.put("success", success);

        logSecurityEvent(
            success ? SecurityEvent.LOGIN_SUCCESS : SecurityEvent.LOGIN_FAILURE,
            username,
            "USER_SESSION",
            null,
            data
        );
    }

    public void logDataAccess(String userId, String dataType, String recordId) {
        Map<String, Object> data = new HashMap<>();
        data.put("data_classification", getDataClassification(dataType));

        logSecurityEvent(
            SecurityEvent.SENSITIVE_DATA_ACCESS,
            userId,
            dataType,
            recordId,
            data
        );
    }

    private String getDataClassification(String dataType) {
        // Implement classification logic
        return "CONFIDENTIAL";
    }
}

