package com.ansvar.service;

import com.ansvar.security.logging.SecurityLogger;
import org.springframework.stereotype.Service;

@Service
public class UserService {

    private final SecurityLogger securityLogger;

    public UserService(SecurityLogger securityLogger) {
        this.securityLogger = securityLogger;
    }

    public void promoteUserToAdmin(String userId, String targetUserId) {
        // Business logic
        userRepository.updateRole(targetUserId, Role.ADMIN);

        // Log security-relevant action
        Map<String, Object> eventData = new HashMap<>();
        eventData.put("promoted_by", userId);
        eventData.put("new_role", "ADMIN");
        eventData.put("previous_role", "USER");

        securityLogger.logSecurityEvent(
            SecurityEvent.PRIVILEGE_ESCALATION,
            targetUserId,
            "USER_ROLE",
            targetUserId,
            eventData
        );
    }
}
